    def compute_progress_ratio(self, x: float, y: float) -> float:
        goal_dx = self.goal_x - self.start_x
        goal_dy = self.goal_y - self.start_y
        denom = goal_dx * goal_dx + goal_dy * goal_dy
        if denom <= 1e-6:
